/// Extracts a team slug from a pattern ID generated by the sports library.
///
/// Pattern IDs follow the format: `gen_team_{league}_{team}_fx_{effectId}`
/// Team slugs in kTeamColors follow: `{league}_{team}`
///
/// Returns null if the pattern is not team-associated.
String? teamSlugFromPatternId(String patternId) {
  // Pattern IDs from sports library: gen_team_nfl_cowboys_fx_12
  if (!patternId.startsWith('gen_team_')) return null;

  final withoutPrefix = patternId.substring('gen_team_'.length);
  final fxIndex = withoutPrefix.indexOf('_fx_');
  if (fxIndex < 0) return null;

  final slug = withoutPrefix.substring(0, fxIndex);
  // Verify this slug exists in our team database.
  if (kTeamColors.containsKey(slug)) return slug;

  return null;
}

/// After a user applies a team-associated design, check if that team has a
/// game within 24 hours. If so, show a friendly prompt offering to enable
/// live scoring for the game.
///
/// Call this after a successful apply. It's a no-op if:
/// - The pattern is not team-associated
/// - No game found within 24h
/// - User declines
Future<void> maybePromptLiveScoring({
  required BuildContext context,
  required WidgetRef ref,
  required String patternId,
}) async {
  final teamSlug = teamSlugFromPatternId(patternId);
  if (teamSlug == null) return;

  final teamInfo = kTeamColors[teamSlug];
  if (teamInfo == null) return;

  // Check for a game within 24h.
  GameState? game;
  try {
    game = await ref.read(activeGameProvider(teamSlug).future);
  } catch (_) {
    return; // ESPN fetch failed — silently skip.
  }
  if (game == null) return;
  if (!context.mounted) return;

  final isLive = game.status == GameStatus.inProgress ||
      game.status == GameStatus.halftime;
  final isScheduled = game.status == GameStatus.scheduled;

  if (!isLive && !isScheduled) return; // Game is final — no point.

  final matchup = '${game.awayTeam} @ ${game.homeTeam}';
  final statusText = isLive
      ? 'Live now! ${game.homeScore} - ${game.awayScore}'
      : 'Today';

  final accepted = await showModalBottomSheet<bool>(
    context: context,
    backgroundColor: NexGenPalette.gunmetal,
    shape: const RoundedRectangleBorder(
      borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
    ),
    builder: (ctx) => _LiveScoringPromptSheet(
      teamName: teamInfo.teamName,
      matchup: matchup,
      statusText: statusText,
      isLive: isLive,
      primaryColor: teamInfo.primary,
      secondaryColor: teamInfo.secondary,
    ),
  );

  if (accepted != true) return;
  if (!context.mounted) return;

  // Add a ScoreAlertConfig for this team so the existing background
  // service picks it up and starts monitoring. If a config already
  // exists for this team, this is a no-op (the service de-duplicates).
  try {
    final existing = ref.read(sportsAlertConfigsProvider);
    final alreadyTracked = existing.any((c) => c.teamSlug == teamSlug);

    if (!alreadyTracked) {
      final config = ScoreAlertConfig(
        id: 'gameday_adhoc_$teamSlug',
        teamSlug: teamSlug,
        sport: teamInfo.sport,
        isEnabled: true,
      );
      await ref.read(sportsAlertConfigsProvider.notifier).addConfig(config);
    }

    if (context.mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
              'Live scoring enabled for ${teamInfo.teamName}! '
              'Your lights will celebrate every score.'),
          duration: const Duration(seconds: 3),
        ),
      );
    }
  } catch (_) {
    // Alert service not available — skip silently.
  }
}

